import React from "react";
import styles from "./product-info.module.css";
import Title from "../../title";
import Quantity from "../quantity";
import Subscription from "../subscription";
import ButtonAdd from "../button-add";
import Details from "../details";

interface InfoProps {
  name: string;
  price: number;
}

const ProductInfo: React.FC<InfoProps> = ({ name, price }) => {
  return (
    <div className={styles.wrapper_product_info}>
      <Title level="h3" className={styles.title}>
        {name} Candleaf®
      </Title>
      <div className={styles.container_inner}>
        <div className={styles.container_left}>
          <span className={styles.price}>${price}</span>
          <div className={styles.wrapper_quantity}>
            <h6 className={styles.quantity_title}>Quantity</h6>

          <Quantity />
          </div>
        </div>
        <div className={styles.container_right}>
          <Subscription />
          <ButtonAdd imgSrc={`${process.env.PUBLIC_URL}/images/Cart-white.svg`} text="+ Add to cart" />
        </div>
      </div>
      <Details />
    </div>
  );
};

export default ProductInfo;
